    73→
    74→/* On all supported linux kernels /proc/self/maps -> /proc/$pid/maps
    75→ * However, what we want is /proc/$tid/maps, so we can't use "self"
    76→ */
    77→#define PROC_SELF_MAPS "/proc/self/maps"
    78→
    79→/* these are defined in /usr/src/linux/fs/proc/array.c */
    80→#define MAPS_LINE_LENGTH 4096
    81→/* for systems with sizeof(void*) == 4: */
    82→#define MAPS_LINE_FORMAT4 "%08lx-%08lx %s %08lx %*s " UINT64_FORMAT_STRING " %4096[^\n]"
    83→#define MAPS_LINE_MAX4 49 /* sum of 8  1  8  1 4 1 8 1 5 1 10 1 */
    84→/* for systems with sizeof(void*) == 8: */
    85→#define MAPS_LINE_FORMAT8 \
    86→    "%016lx-%016lx %s %016lx %*s " UINT64_FORMAT_STRING " %4096[^\n]"
    87→#define MAPS_LINE_MAX8 73 /* sum of 16  1  16  1 4 1 16 1 5 1 10 1 */
    88→
    89→#define MAPS_LINE_MAX MAPS_LINE_MAX8
