    97→ */
    98→#define BUFSIZE (MAPS_LINE_LENGTH + 8)
    99→static char buf_scratch[BUFSIZE];
   100→static char comment_buf_scratch[BUFSIZE];
   101→/* To satisfy our two uses (inner use with memory_info_buf_lock versus
   102→ * outer use with maps_iter_buf_lock), we have two different locks and
   103→ * two different sets of static buffers.  This is to avoid lock
   104→ * ordering issues: we need an inner lock for use in places like signal
   105→ * handlers, but an outer lock when the iterator user allocates memory.
   106→ */
   107→static char buf_iter[BUFSIZE];
   108→static char comment_buf_iter[BUFSIZE];
   109→
   110→void
   111→memquery_init(void)
   112→{
   113→    /* XXX: if anything substantial is added here, the memquery use
   114→     * in privload_early_inject() will have to be re-evaluated.
   115→     */
   116→    ASSERT(sizeof(maps_iter_t) <= MEMQUERY_INTERNAL_DATA_LEN);
   117→}
   118→
   119→void
   120→memquery_exit(void)
   121→{
   122→    DELETE_LOCK(memory_info_buf_lock);
   123→    DELETE_LOCK(maps_iter_buf_lock);
   124→}
   125→
   126→bool
   127→memquery_from_os_will_block(void)
   128→{
   129→#ifdef DEADLOCK_AVOIDANCE
   130→    return memory_info_buf_lock.owner != INVALID_THREAD_ID;
   131→#else
   132→    /* "may_alloc" is false for memquery_from_os() */
   133→    bool res = true;
   134→    if (d_r_mutex_trylock(&memory_info_buf_lock)) {
   135→        res = false;
   136→        d_r_mutex_unlock(&memory_info_buf_lock);
   137→    }
   138→    return res;
   139→#endif
   140→}
   141→
   142→bool
   143→memquery_iterator_start(memquery_iter_t *iter, app_pc start, bool may_alloc)
   144→{
   145→    char maps_name[24]; /* should only need 16 for 5-digit tid */
   146→    maps_iter_t *mi = (maps_iter_t *)&iter->internal;
   147→
   148→    /* Don't assign the local ptrs until the lock is grabbed to make
   149→     * their relationship clear. */
   150→    if (may_alloc) {
   151→        d_r_mutex_lock(&maps_iter_buf_lock);
   152→        mi->buf = (char *)&buf_iter;
   153→        mi->comment_buffer = (char *)&comment_buf_iter;
   154→    } else {
   155→        d_r_mutex_lock(&memory_info_buf_lock);
   156→        mi->buf = (char *)&buf_scratch;
   157→        mi->comment_buffer = (char *)&comment_buf_scratch;
   158→    }
   159→
   160→    /* We need the maps for our thread id, not process id.
   161→     * "/proc/self/maps" uses pid which fails if primary thread in group
   162→     * has exited.
   163→     */
   164→    snprintf(maps_name, BUFFER_SIZE_ELEMENTS(maps_name), "/proc/%d/maps",
   165→             d_r_get_thread_id());
   166→    mi->maps = os_open(maps_name, OS_OPEN_READ);
   167→    ASSERT(mi->maps != INVALID_FILE);
   168→    mi->buf[BUFSIZE - 1] = '\0'; /* permanently */
   169→
   170→    mi->newline = NULL;
   171→    mi->bufread = 0;
   172→    iter->comment = mi->comment_buffer;
   173→
   174→    iter->may_alloc = may_alloc;
   175→
   176→    /* XXX: it's quite difficult to start at the region containing "start":
   177→     * we either need to support walking backward a line (complicated by
   178→     * the incremental os_read() scheme) or make two passes.
   179→     * Thus, the interface doesn't promise we'll start there.
   180→     */
   181→    iter->vm_start = NULL;
   182→
   183→    return true;
   184→}
   185→
   186→void
   187→memquery_iterator_stop(memquery_iter_t *iter)
   188→{
   189→    maps_iter_t *mi = (maps_iter_t *)&iter->internal;
   190→    ASSERT((iter->may_alloc && OWN_MUTEX(&maps_iter_buf_lock)) ||
   191→           (!iter->may_alloc && OWN_MUTEX(&memory_info_buf_lock)));
   192→    os_close(mi->maps);
   193→    if (iter->may_alloc)
   194→        d_r_mutex_unlock(&maps_iter_buf_lock);
   195→    else
   196→        d_r_mutex_unlock(&memory_info_buf_lock);
   197→}
   198→
   199→bool
   200→memquery_iterator_next(memquery_iter_t *iter)
   201→{
   202→    maps_iter_t *mi = (maps_iter_t *)&iter->internal;
   203→    char perm[16];
   204→    char *line;
   205→    int len;
   206→    app_pc prev_start = iter->vm_start;
   207→    ASSERT((iter->may_alloc && OWN_MUTEX(&maps_iter_buf_lock)) ||
   208→           (!iter->may_alloc && OWN_MUTEX(&memory_info_buf_lock)));
   209→    if (mi->newline == NULL) {
   210→        mi->bufwant = BUFSIZE - 1;
   211→        mi->bufread = os_read(mi->maps, mi->buf, mi->bufwant);
   212→        ASSERT(mi->bufread <= mi->bufwant);
   213→        LOG(GLOBAL, LOG_VMAREAS, 6, "get_memory_info_from_os: bytes read %d/want %d\n",
   214→            mi->bufread, mi->bufwant);
   215→        if (mi->bufread <= 0)
   216→            return false;
   217→        mi->buf[mi->bufread] = '\0';
   218→        mi->newline = strchr(mi->buf, '\n');
   219→        line = mi->buf;
   220→    } else {
   221→        line = mi->newline + 1;
   222→        mi->newline = strchr(line, '\n');
   223→        if (mi->newline == NULL) {
   224→            /* XXX clean up: factor out repetitive code */
   225→            /* shift 1st part of line to start of buf, then read in rest */
   226→            /* the memory for the processed part can be reused  */
   227→            mi->bufwant = line - mi->buf;
   228→            ASSERT(mi->bufwant <= mi->bufread);
   229→            len = mi->bufread - mi->bufwant; /* what is left from last time */
   230→            /* since strings may overlap, should use memmove, not strncpy */
   231→            /* XXX corner case: if len == 0, nothing to move */
   232→            memmove(mi->buf, line, len);
   233→            mi->bufread = os_read(mi->maps, mi->buf + len, mi->bufwant);
   234→            ASSERT(mi->bufread <= mi->bufwant);
   235→            if (mi->bufread <= 0)
   236→                return false;
   237→            mi->bufread += len; /* bufread is total in buf */
   238→            mi->buf[mi->bufread] = '\0';
   239→            mi->newline = strchr(mi->buf, '\n');
   240→            line = mi->buf;
   241→        }
   242→    }
   243→    LOG(GLOBAL, LOG_VMAREAS, 6, "\nget_memory_info_from_os: newline=[%.*s]\n",
   244→        /* Limit the size to avoid crossing the log buffer threshold.
   245→         * We could be in a fragile place and don't want a heap alloc.
   246→         */
   247→        MAX_LOG_LENGTH - 128, mi->newline ? mi->newline : "(null)");
   248→
   249→    /* Buffer is big enough to hold at least one line: if not, the file changed
   250→     * underneath us after we hit the end.  Just bail.
   251→     */
   252→    if (mi->newline == NULL)
   253→        return false;
   254→    *mi->newline = '\0';
   255→    LOG(GLOBAL, LOG_VMAREAS, 6, "\nget_memory_info_from_os: line=[%s]\n", line);
   256→    mi->comment_buffer[0] = '\0';
   257→    len = sscanf(line, sizeof(void *) == 4 ? MAPS_LINE_FORMAT4 : MAPS_LINE_FORMAT8,
   258→                 (unsigned long *)&iter->vm_start, (unsigned long *)&iter->vm_end, perm,
   259→                 (unsigned long *)&iter->offset, &iter->inode, mi->comment_buffer);
   260→    if (iter->vm_start == iter->vm_end) {
   261→        /* i#366 & i#599: Merge an empty regions caused by stack guard pages
   262→         * into the stack region if the stack region is less than one page away.
   263→         * Otherwise skip it.  Some Linux kernels (2.6.32 has been observed)
   264→         * have empty entries for the stack guard page.  We drop the permissions
   265→         * on the guard page, because Linux always insists that it has rwxp
   266→         * perms, no matter how we change the protections.  The actual stack
   267→         * region has the perms we expect.
   268→         * XXX: We could get more accurate info if we looked at
   269→         * /proc/self/smaps, which has a Size: 4k line for these "empty"
   270→         * regions.
   271→         */
   272→        app_pc empty_start = iter->vm_start;
   273→        bool r;
   274→        LOG(GLOBAL, LOG_VMAREAS, 2,
   275→            "maps_iterator_next: skipping or merging empty region 0x%08x\n",
   276→            iter->vm_start);
   277→        /* don't trigger the maps-file-changed check.
   278→         * slight risk of a race where we'll pass back earlier/overlapping
   279→         * region: we'll live with it.
   280→         */
   281→        iter->vm_start = NULL;
   282→        r = memquery_iterator_next(iter);
   283→        /* We could check to see if we're combining with the [stack] section,
   284→         * but that doesn't work if there are multiple stacks or the stack is
   285→         * split into multiple maps entries, so we merge any empty region within
   286→         * one page of the next region.
   287→         */
   288→        if (empty_start <= iter->vm_start && iter->vm_start <= empty_start + PAGE_SIZE) {
   289→            /* Merge regions if the next region was zero or one page away. */
   290→            iter->vm_start = empty_start;
   291→        }
   292→        return r;
   293→    }
   294→    if (iter->vm_start <= prev_start) {
   295→        /* the maps file has expanded underneath us (presumably due to our
   296→         * own committing while iterating): skip ahead */
   297→        LOG(GLOBAL, LOG_VMAREAS, 2,
   298→            "maps_iterator_next: maps file changed: skipping 0x%08x\n", prev_start);
   299→        iter->vm_start = prev_start;
   300→        return memquery_iterator_next(iter);
   301→    }
   302→    if (len < 6)
   303→        mi->comment_buffer[0] = '\0';
   304→    iter->prot = permstr_to_memprot(perm);
   305→#ifdef ANDROID
   306→    /* i#1861: the Android kernel supports custom comments which can't merge */
   307→    if (iter->comment[0] != '\0')
   308→        iter->prot |= MEMPROT_HAS_COMMENT;
   309→#endif
   310→    return true;
   311→}
   312→
   313→/***************************************************************************
   314→ * LIBRARY BOUNDS
   315→ */
   316→
   317→/* See memquery.h for full interface specs.
   318→ * Gets the library bounds from walking the map file (as opposed to using our cached
   319→ * module_list) since is only used for dr and client libraries which aren't on the list.
   320→ */
   321→int
   322→memquery_library_bounds(const char *name, app_pc *start /*IN/OUT*/, app_pc *end /*OUT*/,
   323→                        char *fulldir /*OPTIONAL OUT*/, size_t fulldir_size,
   324→                        char *filename /*OPTIONAL OUT*/, size_t filename_size)
   325→{
   326→    return memquery_library_bounds_by_iterator(name, start, end, fulldir, fulldir_size,
   327→                                               filename, filename_size);
   328→}
   329→
   330→/***************************************************************************
   331→ * QUERY
   332→ */
   333→
   334→bool
   335→memquery_from_os(const byte *pc, DR_PARAM_OUT dr_mem_info_t *info,
   336→                 DR_PARAM_OUT bool *have_type)
   337→{
   338→    memquery_iter_t iter;
   339→    app_pc last_end = NULL;
   340→    app_pc next_start = (app_pc)POINTER_MAX;
   341→    bool found = false;
   342→    ASSERT(info != NULL);
   343→    memquery_iterator_start(&iter, (app_pc)pc, false /*won't alloc*/);
   344→    while (memquery_iterator_next(&iter)) {
   345→        if (pc >= iter.vm_start && pc < iter.vm_end) {
   346→            info->base_pc = iter.vm_start;
   347→            info->size = (iter.vm_end - iter.vm_start);
   348→            info->prot = iter.prot;
   349→            /* On early (pre-Fedora 2) kernels the vsyscall page is listed
   350→             * with no permissions at all in the maps file.  Here's RHEL4:
   351→             *   ffffe000-fffff000 ---p 00000000 00:00 0
   352→             * We return "rx" as the permissions in that case.
   353→             */
   354→            if (vdso_page_start != NULL && pc >= vdso_page_start &&
   355→                pc < vdso_page_start + vdso_size) {
   356→                /* i#1583: recent kernels have 2-page vdso, which can be split into
   357→                 * pieces by our vsyscall hook, so we don't check for a precise match.
   358→                 */
   359→                info->prot = (MEMPROT_READ | MEMPROT_EXEC | MEMPROT_VDSO);
   360→            } else if (strcmp(iter.comment, "[vvar]") == 0) {
   361→                /* The VVAR pages were added in kernel 3.0 but not labeled until
   362→                 * 3.15.  We document that we do not label prior to 3.15.
   363→                 * DrMem#1778 seems to only happen on 3.19+ in any case.
   364→                 */
   365→                info->prot |= MEMPROT_VDSO;
   366→            }
   367→            found = true;
   368→            break;
   369→        } else if (pc < iter.vm_start) {
   370→            next_start = iter.vm_start;
   371→            break;
   372→        }
   373→        last_end = iter.vm_end;
   374→    }
   375→    memquery_iterator_stop(&iter);
   376→    if (!found) {
   377→        info->base_pc = last_end;
   378→        info->size = (next_start - last_end);
   379→        info->prot = MEMPROT_NONE;
   380→        info->type = DR_MEMTYPE_FREE;
   381→        *have_type = true;
   382→    }
   383→    return true;
   384→}
