    46→/* We do not synchronize access because we assume the itimer is shared
    47→ * for the thread group, there's just one thread group, and the itimer
    48→ * signal is blocked while in the handler.
    49→ */
    50→static int buckets[DR_WHERE_LAST];
    51→
    52→/* Currently only written to but we may add checks on this once i#4669 failures
    53→ * are fixed.
    54→ */
    55→static int xl8_failures;
    56→
    57→/* test PR 368737: add client timer support */
    58→static void
    59→event_timer(void *drcontext, dr_mcontext_t *mcontext)
    60→{
    61→    dr_fprintf(STDERR, "client event_timer fired\n");
    62→}
    63→
    64→/* Test i#140: add client pc sampling support */
    65→static void
    66→event_sample(void *drcontext, dr_mcontext_t *mcontext)
    67→{
    68→    void *tag;
    69→    dr_where_am_i_t whereami = dr_where_am_i(drcontext, mcontext->pc, &tag);
    70→    buckets[whereami]++;
    71→    DR_ASSERT(mcontext->pc != NULL &&
    72→              /* Ensure DR wrote the value and it's not the uninit 0xab pattern. */
    73→              mcontext->pc != (app_pc)IF_X64_ELSE(0xabababababababab, 0xabababab));
    74→#if VERBOSE
    75→    dr_fprintf(STDERR, "sample: %p %d %p\n", mcontext->pc, whereami, tag);
    76→#endif
    77→    if (whereami == DR_WHERE_FCACHE) {
    78→        /* Ask for translation to test i#4669. */
    79→        app_pc xl8 = dr_app_pc_from_cache_pc(mcontext->pc);
    80→        if (xl8 == NULL)
    81→            ++xl8_failures;
    82→    }
    83→}
    84→
    85→static void
    86→post_syscall_event(void *drcontext, int sysnum)
    87→{
    88→    if (sysnum != SYS_setitimer)
    89→        return;
    90→    /* Test i#2805: now that the app's alarm is set up, we want to try to hit the
    91→     * race window where a signal enters record_pending_signal() while the thread
    92→     * is marked as a safe spot yet holds its synch_lock in the middle of
    93→     * dr_mark_safe_to_suspend(,false)).  If we hit the window, without the
    94→     * proper i#2805 fix, we see a hang (or rank order violations in debug).
    95→     */
    96→    static volatile bool test_i2805;
    97→    if (!test_i2805) {
    98→        int i;
    99→#define TEST_ITERS 500000
   100→        test_i2805 = true;
   101→        for (i = 0; i < TEST_ITERS; ++i) {
   102→            dr_mark_safe_to_suspend(dr_get_current_drcontext(), true);
   103→            dr_mark_safe_to_suspend(dr_get_current_drcontext(), false);
   104→        }
   105→    }
   106→}
   107→
   108→static bool
   109→filter_syscall_event(void *drcontext, int sysnum)
   110→{
   111→    return sysnum == SYS_setitimer;
   112→}
   113→
   114→static void
   115→exit_event(void)
   116→{
   117→    int i;
   118→    int total = 0;
   119→    for (i = 0; i < DR_WHERE_LAST; i++) {
   120→        total += buckets[i];
   121→#if VERBOSE
   122→        dr_fprintf(STDERR, "bucket %d: %d\n", i, buckets[i]);
   123→#endif
   124→    }
   125→    DR_ASSERT(total > 0);
   126→}
   127→
   128→DR_EXPORT
   129→void
   130→dr_init(client_id_t id)
   131→{
   132→    dr_register_exit_event(exit_event);
   133→    dr_register_post_syscall_event(post_syscall_event);
   134→    dr_register_filter_syscall_event(filter_syscall_event);
   135→    dr_track_where_am_i();
   136→    DR_ASSERT(dr_is_tracking_where_am_i());
   137→    if (!dr_set_itimer(ITIMER_REAL, 25, event_timer))
   138→        dr_fprintf(STDERR, "unable to set timer callback\n");
